function cleanString(value) {
  return String(value ?? "")
    .replace(/\s+/g, " ")
    .trim();
}

function parseList(value) {
  const entries = cleanString(value)
    .split(/[,;|]/)
    .map((entry) => entry.trim())
    .filter(Boolean);

  // Remove duplicates while ignoring case.
  return [
    ...new Map(
      entries.map((entry) => [
        entry.toLowerCase(),
        entry,
      ])
    ).values(),
  ];
}

function parseNumber(value, fallback, minimum, maximum) {
  const parsed = Number(value);

  if (!Number.isFinite(parsed)) {
    return fallback;
  }

  return Math.min(
    Math.max(Math.round(parsed), minimum),
    maximum
  );
}

function parseBoolean(value) {
  if (typeof value === "boolean") {
    return value;
  }

  return ["true", "yes", "1"].includes(
    cleanString(value).toLowerCase()
  );
}

function normalizeUrl(value) {
  const rawUrl = cleanString(value);

  if (!rawUrl) {
    return null;
  }

  try {
    const url = new URL(rawUrl);

    // Remove common tracking parameters.
    const trackingParameters = [
      "utm_source",
      "utm_medium",
      "utm_campaign",
      "utm_term",
      "utm_content",
      "fbclid",
      "gclid",
      "ref",
      "source",
    ];

    for (const parameter of trackingParameters) {
      url.searchParams.delete(parameter);
    }

    url.hash = "";

    return url
      .toString()
      .replace(/\/$/, "")
      .toLowerCase();
  } catch {
    return rawUrl
      .replace(/\/$/, "")
      .toLowerCase();
  }
}

function getKarachiDate() {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Asia/Karachi",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).formatToParts(new Date());

  const dateParts = Object.fromEntries(
    parts
      .filter((part) => part.type !== "literal")
      .map((part) => [part.type, part.value])
  );

  return `${dateParts.year}-${dateParts.month}-${dateParts.day}`;
}

// Read all rows returned by the Preferences node.
const preferenceRows = $("Read Preferences")
  .all()
  .map((item) => item.json)
  .filter(
    (row) =>
      row &&
      Object.keys(row).length > 0 &&
      parseBoolean(row.active)
  );

if (preferenceRows.length === 0) {
  throw new Error(
    'No active preference row was found. Add a row to the "Preferences" sheet with active set to TRUE.'
  );
}

const preference = preferenceRows[0];

const interests = parseList(preference.interests);
const opportunityTypes = parseList(
  preference.opportunity_types
);
const locations = parseList(preference.locations);
const keywords = parseList(preference.keywords);

if (interests.length === 0) {
  throw new Error(
    "The active preference row must contain at least one interest."
  );
}

if (opportunityTypes.length === 0) {
  throw new Error(
    "The active preference row must contain at least one opportunity type."
  );
}

if (locations.length === 0) {
  throw new Error(
    "The active preference row must contain at least one location."
  );
}

// Read saved opportunities.
// The empty item produced by Always Output Data is removed.
const existingOpportunities = $(
  "Read Opportunity History"
)
  .all()
  .map((item) => item.json)
  .filter(
    (row) =>
      row &&
      Object.keys(row).length > 0 &&
      (cleanString(row.source_url) ||
        cleanString(row.title))
  )
  .map((row) => ({
    opportunity_id:
      cleanString(row.opportunity_id) || null,

    title:
      cleanString(row.title) || null,

    organizer:
      cleanString(row.organizer) || null,

    opportunity_type:
      cleanString(row.opportunity_type) || null,

    deadline:
      cleanString(row.deadline) || null,

    source_url:
      cleanString(row.source_url) || null,

    normalized_url:
      normalizeUrl(
        row.normalized_url || row.source_url
      ),

    status:
      cleanString(row.status) || null,
  }));

const today = getKarachiDate();

const minimumScore = parseNumber(
  preference.minimum_score,
  70,
  0,
  100
);

const reminderDaysBefore = parseNumber(
  preference.reminder_days_before,
  7,
  0,
  90
);

const maximumResults = parseNumber(
  preference.maximum_results,
  5,
  1,
  10
);

const runId = [
  "opportunity-radar",
  today,
  Date.now(),
].join("-");

return [
  {
    json: {
      run_id: runId,

      today,

      timezone: "Asia/Karachi",

      preferences: {
        preference_id:
          cleanString(preference.preference_id) ||
          "primary",

        user_name:
          cleanString(preference.user_name) ||
          null,

        email:
          cleanString(preference.email)
            .toLowerCase() || null,

        interests,

        opportunity_types: opportunityTypes,

        locations,

        experience_level:
          cleanString(
            preference.experience_level
          ) || null,

        keywords,

        minimum_score: minimumScore,

        reminder_days_before:
          reminderDaysBefore,

        maximum_results: maximumResults,
      },

      existing_opportunities:
        existingOpportunities,

      existing_opportunity_count:
        existingOpportunities.length,

      research_rules: {
        return_only_public_opportunities: true,

        prefer_official_sources: true,

        exclude_expired_opportunities: true,

        exclude_existing_urls: true,

        require_source_url: true,

        maximum_new_results:
          maximumResults,
      },
    },
  },
];

