parameters.jsCode:
const formatterResult =
  $input.first()?.json ?? {};

const context =
  $("Build Research Context").first()?.json ?? {};

function cleanString(value) {
  return String(value ?? "")
    // Remove invisible zero-width characters that can
    // quietly break otherwise valid URLs and comparisons.
    .replace(/[\u200B-\u200D\uFEFF]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeText(value) {
  return cleanString(value)
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function parseFormatterOutput(value) {
  let parsed = value;

  // Some n8n versions place the parsed object
  // inside an "output" property.
  while (
    parsed &&
    typeof parsed === "object" &&
    parsed.output !== undefined &&
    !Array.isArray(parsed.opportunities)
  ) {
    parsed = parsed.output;
  }

  if (typeof parsed === "string") {
    const cleaned = parsed
      .replace(/^```(?:json)?\s*/i, "")
      .replace(/\s*```$/i, "")
      .trim();

    try {
      parsed = JSON.parse(cleaned);
    } catch (error) {
      throw new Error(
        `Could not parse the formatter result as JSON: ${error.message}`
      );
    }
  }

  if (
    !parsed ||
    typeof parsed !== "object" ||
    !Array.isArray(parsed.opportunities)
  ) {
    throw new Error(
      'The formatter result does not contain an "opportunities" array.'
    );
  }

  return parsed;
}

function sanitizeUrlInput(value) {
  let raw = cleanString(value);

  if (!raw) {
    return "";
  }

  // Support a URL accidentally returned as:
  // <https://example.com>
  // "https://example.com"
  // `https://example.com`
  raw = raw
    .replace(/^["'`<]+/, "")
    .replace(/["'`>]+$/, "")
    .trim();

  // Support a Markdown URL:
  // [Official page](https://example.com)
  const markdownMatch = raw.match(
    /^\[[^\]]*]\((https?:\/\/[^)]+)\)$/i
  );

  if (markdownMatch) {
    raw = markdownMatch[1];
  }

  return raw.trim();
}

function normalizeUrl(value) {
  const raw = sanitizeUrlInput(value);

  if (!raw) {
    return null;
  }

  // Basic public HTTP/HTTPS validation.
  if (!/^https?:\/\/[^\s]+$/i.test(raw)) {
    return null;
  }

  /*
   * Use the standard URL parser when available.
   * Some restricted n8n Code environments may not
   * expose it, so manual parsing exists below.
   */
  try {
    if (typeof URL !== "undefined") {
      const url = new URL(raw);

      if (
        url.protocol !== "http:" &&
        url.protocol !== "https:"
      ) {
        return null;
      }

      url.protocol =
        url.protocol.toLowerCase();

      url.hostname =
        url.hostname.toLowerCase();

      url.hash = "";

      const removableParameters = [
        "fbclid",
        "gclid",
        "ref",
        "source"
      ];

      for (
        const key of
        [...url.searchParams.keys()]
      ) {
        const normalizedKey =
          key.toLowerCase();

        if (
          normalizedKey.startsWith("utm_") ||
          removableParameters.includes(
            normalizedKey
          )
        ) {
          url.searchParams.delete(key);
        }
      }

      url.searchParams.sort();

      return url
        .toString()
        .replace(/\/$/, "");
    }
  } catch {
    // Fall through to manual parsing.
  }

  /*
   * Manual fallback for n8n environments where
   * the standard URL constructor is unavailable.
   */
  const withoutHash =
    raw.split("#")[0];

  const match = withoutHash.match(
    /^(https?):\/\/([^/?#\s]+)([^?#\s]*)?(?:\?([^#\s]*))?$/i
  );

  if (!match) {
    return null;
  }

  const protocol =
    match[1].toLowerCase();

  const hostname =
    match[2].toLowerCase();

  let pathname =
    match[3] || "";

  if (pathname === "/") {
    pathname = "";
  } else {
    pathname = pathname.replace(
      /\/$/,
      ""
    );
  }

  const removableParameters =
    new Set([
      "fbclid",
      "gclid",
      "ref",
      "source"
    ]);

  const queryParts =
    (match[4] || "")
      .split("&")
      .filter(Boolean)
      .filter((part) => {
        const rawKey =
          part.split("=")[0] || "";

        let key;

        try {
          key = decodeURIComponent(
            rawKey
          ).toLowerCase();
        } catch {
          key = rawKey.toLowerCase();
        }

        return (
          !key.startsWith("utm_") &&
          !removableParameters.has(key)
        );
      })
      .sort();

  const query =
    queryParts.length > 0
      ? `?${queryParts.join("&")}`
      : "";

  return `${protocol}://${hostname}${pathname}${query}`;
}

function getDomain(value) {
  const normalized =
    normalizeUrl(value);

  if (!normalized) {
    return null;
  }

  const match = normalized.match(
    /^https?:\/\/([^/?#]+)/i
  );

  if (!match) {
    return null;
  }

  return match[1]
    .toLowerCase()
    .replace(/^www\./, "");
}

function validateISODate(value, today) {
  const dateText = cleanString(value);

  if (!dateText) {
    return {
      value: null,
      valid: true,
      expired: false
    };
  }

  if (!/^\d{4}-\d{2}-\d{2}$/.test(dateText)) {
    return {
      value: null,
      valid: false,
      expired: false
    };
  }

  const [year, month, day] = dateText
    .split("-")
    .map(Number);

  const parsedDate = new Date(
    Date.UTC(year, month - 1, day)
  );

  const isRealDate =
    parsedDate.getUTCFullYear() === year &&
    parsedDate.getUTCMonth() === month - 1 &&
    parsedDate.getUTCDate() === day;

  if (!isRealDate) {
    return {
      value: null,
      valid: false,
      expired: false
    };
  }

  return {
    value: dateText,
    valid: true,
    expired:
      Boolean(today) &&
      dateText < today
  };
}

function canonicalOpportunityType(value) {
  const type = normalizeText(value);

  const mappings = {
    hackathon: "hackathon",
    hackathons: "hackathon",

    competition: "competition",
    competitions: "competition",
    challenge: "competition",
    challenges: "competition",

    conference: "conference",
    conferences: "conference",

    "research programme": "research program",
    "research programmes": "research program",
    "research program": "research program",
    "research programs": "research program",

    fellowship: "fellowship",
    fellowships: "fellowship",

    internship: "internship",
    internships: "internship"
  };

  return mappings[type] ?? type;
}

function canonicalParticipationMode(value) {
  const mode = normalizeText(value);

  if (
    mode.includes("remote") ||
    mode.includes("online") ||
    mode.includes("virtual")
  ) {
    return "Remote";
  }

  if (mode.includes("hybrid")) {
    return "Hybrid";
  }

  if (
    mode.includes("on site") ||
    mode.includes("onsite") ||
    mode.includes("in person")
  ) {
    return "On-site";
  }

  return "Unknown";
}

function canonicalConfidence(value) {
  const confidence =
    normalizeText(value);

  if (
    confidence === "high" ||
    confidence === "medium" ||
    confidence === "low"
  ) {
    return confidence;
  }

  return "low";
}

function cleanStringArray(value) {
  const input = Array.isArray(value)
    ? value
    : cleanString(value).split(
        /[|;\n]/
      );

  return [
    ...new Map(
      input
        .map(cleanString)
        .filter(Boolean)
        .map((entry) => [
          normalizeText(entry),
          entry
        ])
    ).values()
  ];
}

function stableHash(value) {
  let hash = 2166136261;

  for (
    let index = 0;
    index < value.length;
    index += 1
  ) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(
      hash,
      16777619
    );
  }

  return (hash >>> 0)
    .toString(16)
    .padStart(8, "0");
}

function titleOrganizerKey(
  title,
  organizer
) {
  const normalizedTitle =
    normalizeText(title);

  const normalizedOrganizer =
    normalizeText(organizer);

  if (
    !normalizedTitle ||
    !normalizedOrganizer
  ) {
    return null;
  }

  return (
    `${normalizedTitle}|` +
    normalizedOrganizer
  );
}

function appearsLocationRelevant(
  location,
  participationMode,
  preferredLocations
) {
  const normalizedPreferences =
    preferredLocations
      .map(normalizeText)
      .filter(Boolean);

  // No location restrictions are available.
  if (
    normalizedPreferences.length === 0
  ) {
    return null;
  }

  // Remote opportunities are acceptable when
  // Remote or Worldwide is in the preferences.
  if (
    participationMode === "Remote" &&
    normalizedPreferences.some(
      (entry) =>
        entry === "remote" ||
        entry === "worldwide"
    )
  ) {
    return true;
  }

  const normalizedLocation =
    normalizeText(location);

  if (!normalizedLocation) {
    return null;
  }

  const directMatch =
    normalizedPreferences.some(
      (preference) =>
        preference !== "remote" &&
        (
          normalizedLocation.includes(
            preference
          ) ||
          preference.includes(
            normalizedLocation
          )
        )
    );

  if (directMatch) {
    return true;
  }

  // Treat individual European countries as matching
  // the broader Europe preference.
  if (
    normalizedPreferences.includes(
      "europe"
    )
  ) {
    const europeanLocations = [
      "albania",
      "andorra",
      "austria",
      "belarus",
      "belgium",
      "bosnia",
      "bulgaria",
      "croatia",
      "cyprus",
      "czech",
      "denmark",
      "estonia",
      "finland",
      "france",
      "germany",
      "greece",
      "hungary",
      "iceland",
      "ireland",
      "italy",
      "kosovo",
      "latvia",
      "liechtenstein",
      "lithuania",
      "luxembourg",
      "malta",
      "moldova",
      "monaco",
      "montenegro",
      "netherlands",
      "north macedonia",
      "norway",
      "poland",
      "portugal",
      "romania",
      "san marino",
      "serbia",
      "slovakia",
      "slovenia",
      "spain",
      "sweden",
      "switzerland",
      "ukraine",
      "united kingdom",
      "england",
      "scotland",
      "wales",
      "europe"
    ];

    if (
      europeanLocations.some(
        (entry) =>
          normalizedLocation.includes(
            entry
          )
      )
    ) {
      return true;
    }
  }

  return false;
}

const parsed =
  parseFormatterOutput(
    formatterResult
  );

const rawOpportunities =
  parsed.opportunities;

const researchSummary =
  parsed.research_summary ?? {
    search_queries: [],
    pages_extracted: 0,
    results_rejected: 0,
    notes: []
  };

const today =
  cleanString(context.today);

const minimumScore =
  Number(
    context.preferences
      ?.minimum_score ?? 70
  );

const maximumResults =
  Number(
    context.preferences
      ?.maximum_results ?? 5
  );

const preferredLocations =
  Array.isArray(
    context.preferences?.locations
  )
    ? context.preferences.locations
    : [];

const allowedTypes = new Set(
  (
    Array.isArray(
      context.preferences
        ?.opportunity_types
    )
      ? context.preferences
          .opportunity_types
      : []
  ).map(canonicalOpportunityType)
);

// Build sets from previously saved opportunities.
const existingUrls = new Set();

const existingTitleOrganizerKeys =
  new Set();

for (
  const existing of
    context.existing_opportunities ?? []
) {
  const normalizedExistingUrl =
    normalizeUrl(
      existing.normalized_url ||
      existing.source_url
    );

  if (normalizedExistingUrl) {
    existingUrls.add(
      normalizedExistingUrl
    );
  }

  const existingKey =
    titleOrganizerKey(
      existing.title,
      existing.organizer
    );

  if (existingKey) {
    existingTitleOrganizerKeys.add(
      existingKey
    );
  }
}

const blockedDomains = [
  "facebook.com",
  "instagram.com",
  "linkedin.com",
  "pinterest.com",
  "tiktok.com",
  "twitter.com",
  "x.com",
  "youtube.com"
];

// Validate higher-scoring results first.
const candidates =
  rawOpportunities
    .map((opportunity) => ({
      ...opportunity,
      relevance_score:
        Number(
          opportunity.relevance_score
        )
    }))
    .sort(
      (first, second) =>
        Number(
          second.relevance_score || 0
        ) -
        Number(
          first.relevance_score || 0
        )
    );

const seenRunUrls = new Set();
const seenRunKeys = new Set();

const outputItems = [];

let acceptedCount = 0;

for (const opportunity of candidates) {
  const rejectionReasons = [];
  const warnings = [];

  const title =
    cleanString(
      opportunity.title
    );

  const organizer =
    cleanString(
      opportunity.organizer
    ) || null;

  const opportunityType =
    canonicalOpportunityType(
      opportunity.opportunity_type
    );

  const sourceUrl =
    sanitizeUrlInput(
      opportunity.source_url
    );

  const normalizedUrl =
    normalizeUrl(sourceUrl);

  const sourceDomain =
    normalizedUrl
      ? getDomain(normalizedUrl)
      : null;

  const originalRelevanceScore =
    Number(
      opportunity.relevance_score
    );

  const dateResult =
    validateISODate(
      opportunity.deadline,
      today
    );

  const participationMode =
    canonicalParticipationMode(
      opportunity.participation_mode
    );

  const eligibility =
    cleanString(
      opportunity.eligibility
    ) || null;

  const location =
    cleanString(
      opportunity.location
    ) || null;

  const whyRelevant =
    cleanStringArray(
      opportunity.why_relevant
    );

  const duplicateKey =
    titleOrganizerKey(
      title,
      organizer
    );

  const locationRelevant =
    appearsLocationRelevant(
      location,
      participationMode,
      preferredLocations
    );

  /*
   * Deterministic score adjustment.
   * An incomplete record should not keep a heroic
   * score merely because an LLM felt generous.
   */
  let adjustedRelevanceScore =
    originalRelevanceScore;

  if (
    Number.isFinite(
      adjustedRelevanceScore
    )
  ) {
    const importantUnknownCount = [
      organizer,
      dateResult.value,
      eligibility,
      location,
      participationMode === "Unknown"
        ? null
        : participationMode
    ].filter(
      (value) => !value
    ).length;

    // Most important fields are unknown.
    if (
      importantUnknownCount >= 4
    ) {
      adjustedRelevanceScore =
        Math.min(
          adjustedRelevanceScore,
          75
        );
    }

    // Both deadline and eligibility are unknown.
    if (
      !dateResult.value &&
      !eligibility
    ) {
      adjustedRelevanceScore =
        Math.min(
          adjustedRelevanceScore,
          80
        );
    }

    // Non-remote opportunity outside the
    // preferred locations.
    if (
      locationRelevant === false &&
      participationMode !== "Remote"
    ) {
      adjustedRelevanceScore =
        Math.min(
          adjustedRelevanceScore,
          60
        );
    }
  }

  if (!title) {
    rejectionReasons.push(
      "missing_title"
    );
  }

  if (!normalizedUrl) {
    rejectionReasons.push(
      "missing_or_invalid_source_url"
    );
  }

  if (
    sourceDomain &&
    blockedDomains.some(
      (blocked) =>
        sourceDomain === blocked ||
        sourceDomain.endsWith(
          `.${blocked}`
        )
    )
  ) {
    rejectionReasons.push(
      "social_media_source"
    );
  }

  if (
    !Number.isFinite(
      adjustedRelevanceScore
    )
  ) {
    rejectionReasons.push(
      "invalid_relevance_score"
    );
  } else if (
    adjustedRelevanceScore <
    minimumScore
  ) {
    rejectionReasons.push(
      "score_below_threshold"
    );
  }

  if (
    allowedTypes.size > 0 &&
    !allowedTypes.has(
      opportunityType
    )
  ) {
    rejectionReasons.push(
      "opportunity_type_not_allowed"
    );
  }

  if (!dateResult.valid) {
    rejectionReasons.push(
      "invalid_deadline_format"
    );
  }

  if (dateResult.expired) {
    rejectionReasons.push(
      "deadline_expired"
    );
  }

  if (
    normalizedUrl &&
    existingUrls.has(
      normalizedUrl
    )
  ) {
    rejectionReasons.push(
      "duplicate_existing_url"
    );
  }

  if (
    duplicateKey &&
    existingTitleOrganizerKeys.has(
      duplicateKey
    )
  ) {
    rejectionReasons.push(
      "duplicate_existing_title_and_organizer"
    );
  }

  if (
    normalizedUrl &&
    seenRunUrls.has(
      normalizedUrl
    )
  ) {
    rejectionReasons.push(
      "duplicate_in_current_run_url"
    );
  }

  if (
    duplicateKey &&
    seenRunKeys.has(
      duplicateKey
    )
  ) {
    rejectionReasons.push(
      "duplicate_in_current_run_title_and_organizer"
    );
  }

  if (
    whyRelevant.length === 0
  ) {
    rejectionReasons.push(
      "missing_relevance_reasons"
    );
  }

  // Reject an on-site or hybrid opportunity in
  // a clearly disallowed location.
  if (
    locationRelevant === false
  ) {
    rejectionReasons.push(
      "location_not_allowed"
    );
  }

  if (!dateResult.value) {
    warnings.push(
      "deadline_not_verified"
    );
  }

  if (!organizer) {
    warnings.push(
      "organizer_not_verified"
    );
  }

  if (!eligibility) {
    warnings.push(
      "eligibility_not_verified"
    );
  }

  if (!location) {
    warnings.push(
      "location_not_verified"
    );
  }

  if (
    participationMode === "Unknown"
  ) {
    warnings.push(
      "participation_mode_not_verified"
    );
  }

  if (
    rejectionReasons.length === 0 &&
    acceptedCount >= maximumResults
  ) {
    rejectionReasons.push(
      "maximum_results_exceeded"
    );
  }

  const accepted =
    rejectionReasons.length === 0;

  if (accepted) {
    acceptedCount += 1;

    if (normalizedUrl) {
      seenRunUrls.add(
        normalizedUrl
      );
    }

    if (duplicateKey) {
      seenRunKeys.add(
        duplicateKey
      );
    }
  }

  const identitySource =
    normalizedUrl ||
    duplicateKey ||
    `${title}|${sourceUrl}`;

  outputItems.push({
    json: {
      record_type:
        "opportunity",

      accepted,

      validation_status:
        accepted
          ? "accepted"
          : "rejected",

      rejection_reasons:
        rejectionReasons,

      validation_warnings:
        warnings,

      opportunity_id:
        `opp_${stableHash(
          identitySource
        )}`,

      discovered_at:
        new Date().toISOString(),

      title,

      opportunity_type:
        cleanString(
          opportunity.opportunity_type
        ) || opportunityType,

      organizer,

      location,

      participation_mode:
        participationMode,

      deadline:
        dateResult.value,

      eligibility,

      relevance_score:
        Number.isFinite(
          adjustedRelevanceScore
        )
          ? Math.min(
              Math.max(
                Math.round(
                  adjustedRelevanceScore
                ),
                0
              ),
              100
            )
          : 0,

      original_relevance_score:
        Number.isFinite(
          originalRelevanceScore
        )
          ? Math.min(
              Math.max(
                Math.round(
                  originalRelevanceScore
                ),
                0
              ),
              100
            )
          : null,

      why_relevant:
        whyRelevant.join(" | "),

      why_relevant_list:
        whyRelevant,

      recommended_action:
        cleanString(
          opportunity.recommended_action
        ) ||
        "Review the official source.",

      source_url:
        sourceUrl || null,

      normalized_url:
        normalizedUrl,

      source_domain:
        sourceDomain,

      deadline_confidence:
        canonicalConfidence(
          opportunity.deadline_confidence
        ),

      calendar_created:
        false,

      status:
        accepted
          ? "new"
          : "rejected",

      research_summary:
        researchSummary
    }
  });
}

// Preserve a result when the Agent found nothing.
