function cleanString(value) {
  return String(value ?? "")
    .replace(/\s+/g, " ")
    .trim();
}

function clampNumber(
  value,
  fallback,
  minimum,
  maximum
) {
  const parsed = Number(value);

  if (!Number.isFinite(parsed)) {
    return fallback;
  }

  return Math.min(
    Math.max(Math.round(parsed), minimum),
    maximum
  );
}

function isISODate(value) {
  return /^\d{4}-\d{2}-\d{2}$/.test(
    cleanString(value)
  );
}

function shiftDate(isoDate, dayAmount) {
  const date = new Date(
    `${isoDate}T00:00:00.000Z`
  );

  date.setUTCDate(
    date.getUTCDate() + dayAmount
  );

  return date
    .toISOString()
    .slice(0, 10);
}

const opportunity = {
  ...original,
  ...savedRow
};

const today =
  cleanString(context.today);

const deadline =
  cleanString(opportunity.deadline);

const deadlineConfidence =
  cleanString(
    opportunity.deadline_confidence
  ).toLowerCase();

const reminderDaysBefore =
  clampNumber(
    context.preferences
      ?.reminder_days_before,
    7,
    0,
    90
  );

let shouldCreateCalendar = true;
let calendarReason = null;
let reminderDate = null;

if (!deadline || !isISODate(deadline)) {
  shouldCreateCalendar = false;
  calendarReason =
    "deadline_missing_or_invalid";
} else if (
  !["high", "medium"].includes(
    deadlineConfidence
  )
) {
  shouldCreateCalendar = false;
  calendarReason =
    "deadline_confidence_too_low";
} else if (deadline < today) {
  shouldCreateCalendar = false;
  calendarReason =
    "deadline_already_passed";
} else {
  const calculatedReminderDate =
    shiftDate(
      deadline,
      -reminderDaysBefore
    );

  // When the preferred reminder day has
  // already passed, create the reminder today.
  reminderDate =
    calculatedReminderDate < today
      ? today
      : calculatedReminderDate;
}

let reminderStart = null;
let reminderEnd = null;

if (shouldCreateCalendar) {
  if (reminderDate === today) {
    // Avoid creating a Calendar event in the
    // past during manual testing.
    reminderStart = new Date(
      Date.now() + 5 * 60 * 1000
    ).toISOString();

    reminderEnd = new Date(
      Date.now() + 35 * 60 * 1000
    ).toISOString();
  } else {
    reminderStart =
      `${reminderDate}T09:00:00+05:00`;

    reminderEnd =
      `${reminderDate}T09:30:00+05:00`;
  }
}

const whyRelevant = Array.isArray(
  opportunity.why_relevant_list
)
  ? opportunity.why_relevant_list
  : cleanString(
      opportunity.why_relevant
    )
      .split("|")
      .map((entry) => entry.trim())
      .filter(Boolean);

const descriptionParts = [
  `Opportunity: ${cleanString(
    opportunity.title
  )}`,

  opportunity.organizer
    ? `Organizer: ${cleanString(
        opportunity.organizer
      )}`
    : null,

  opportunity.opportunity_type
    ? `Type: ${cleanString(
        opportunity.opportunity_type
      )}`
    : null,

  opportunity.location
    ? `Location: ${cleanString(
        opportunity.location
      )}`
    : null,

  opportunity.participation_mode
    ? `Participation mode: ${cleanString(
        opportunity.participation_mode
      )}`
    : null,

  `Actual deadline: ${deadline}`,

  `Relevance score: ${
    opportunity.relevance_score ?? 0
  }/100`,

  opportunity.eligibility
    ? `Eligibility: ${cleanString(
        opportunity.eligibility
      )}`
    : null,

  whyRelevant.length > 0
    ? `Why relevant:\n${whyRelevant
        .map((reason) => `- ${reason}`)
        .join("\n")}`
    : null,

  opportunity.recommended_action
    ? `Recommended action: ${cleanString(
        opportunity.recommended_action
      )}`
    : null,

  opportunity.source_url
    ? `Official source: ${cleanString(
        opportunity.source_url
      )}`
    : null
].filter(Boolean);

return {
  json: {
    ...opportunity,

    should_create_calendar:
      shouldCreateCalendar,

    calendar_reason:
      calendarReason,

    reminder_days_before:
      reminderDaysBefore,

    reminder_date:
      reminderDate,

    reminder_start:
      reminderStart,

    reminder_end:
      reminderEnd,

    calendar_summary:
      `Opportunity deadline: ${
        cleanString(opportunity.title) ||
        "Review application"
      }`,

    calendar_description:
      descriptionParts.join("\n\n"),

    calendar_location:
      cleanString(
        opportunity.location
