const context =
  $("Build Research Context")
    .first()?.json ?? {};

const results = $input
  .all()
  .map((item) => item.json ?? {});

function cleanString(value) {
  return String(value ?? "")
    .replace(/\s+/g, " ")
    .trim();
}

function escapeHtml(value) {
  return cleanString(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function humanize(value) {
  return cleanString(value)
    .replace(/_/g, " ")
    .replace(/\b\w/g, (letter) =>
      letter.toUpperCase()
    );
}

function formatDate(value) {
  const text = cleanString(value);

  if (!/^\d{4}-\d{2}-\d{2}$/.test(text)) {
    return "Not verified";
  }

  const date = new Date(
    `${text}T00:00:00Z`
  );

  return new Intl.DateTimeFormat(
    "en-GB",
    {
      day: "numeric",
      month: "long",
      year: "numeric",
      timeZone: "UTC"
    }
  ).format(date);
}

function getRelevantReasons(opportunity) {
  if (
    Array.isArray(
      opportunity.why_relevant_list
    )
  ) {
    return opportunity
      .why_relevant_list
      .map(cleanString)
      .filter(Boolean);
  }

  return cleanString(
    opportunity.why_relevant
  )
    .split("|")
    .map((reason) => reason.trim())
    .filter(Boolean);
}

const opportunityResults = results.filter(
  (item) =>
    item.record_type === "opportunity"
);

const accepted = opportunityResults
  .filter((item) => item.accepted === true)
  .sort(
    (first, second) =>
      Number(
        second.relevance_score ?? 0
      ) -
      Number(
        first.relevance_score ?? 0
      )
  );

const rejected = opportunityResults.filter(
  (item) => item.accepted !== true
);

const remindersCreated = accepted.filter(
  (item) =>
    item.calendar_created === true
);

const savedWithoutReminder =
  accepted.filter(
    (item) =>
      item.calendar_created !== true
  );

const rejectionCounts = {};

for (const item of rejected) {
  const reasons = Array.isArray(
    item.rejection_reasons
  )
    ? item.rejection_reasons
    : ["unspecified_rejection"];

  for (const reason of reasons) {
    rejectionCounts[reason] =
      (rejectionCounts[reason] ?? 0) + 1;
  }
}

const researchSummary =
  results.find(
    (item) => item.research_summary
  )?.research_summary ?? {};

const userName =
  cleanString(
    context.preferences?.user_name
  ) || "there";

const recipient =
  cleanString(
    context.preferences?.email
  ).toLowerCase();

if (!recipient) {
  throw new Error(
    "The active Preferences row does not contain an email address."
  );
}

const runDate = formatDate(
  context.today
);

const opportunityCards = accepted
  .map((opportunity, index) => {
    const reasons =
      getRelevantReasons(opportunity);

    const reasonsHtml =
      reasons.length > 0
        ? `
          <ul style="margin:8px 0 14px 20px;padding:0;">
            ${reasons
              .map(
                (reason) =>
