          ">
            <strong>${
              remindersCreated.length
            }</strong>
            <br>
            Reminders created
          </td>

          <td style="
            padding:14px;
            background:#ffffff;
            border:1px solid #e5e7eb;
            border-radius:8px;
          ">
            <strong>${rejected.length}</strong>
            <br>
            Results ignored
          </td>
        </tr>
      </table>

      ${noResultsSection}

      ${opportunityCards}

      ${
        rejected.length > 0
          ? `
            <div style="
              margin-top:24px;
              padding:16px;
