  );
}

if (accepted.length === 0) {
  plainTextLines.push(
    "No new verified opportunities matched your preferences."
  );
}

return [
  {
    json: {
      recipient,

      subject,

      html_body: htmlBody,

      plain_text_body:
        plainTextLines.join("\n"),

      digest_metrics: {
        processed:
          opportunityResults.length,

        accepted:
          accepted.length,

        rejected:
          rejected.length,

        reminders_created:
          remindersCreated.length,

        saved_without_reminder:
          savedWithoutReminder.length
      }
    }
  }
];
